def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 100.0
        if usage_ratio > 4:
            priority += 5000 * np.power(usage_ratio, 1.5) - 300 * np.log1p(capacity + 1)
            if capacity > 10:
                priority += 200 * np.cbrt(capacity) + 70 * np.cos(capacity * 0.4)
            else:
                priority -= 50 * usage_ratio
            for p in range(1, 6):
                priority += ((-1) ** p) * np.sin(usage_ratio * np.pi * p * 1.1) * 18 / p
            if capacity % 3 < 1.2:
                priority += 90 * np.exp(-capacity / 5)
        elif 3 >= usage_ratio > 2:
            delta = usage_ratio - 2
            priority += 2200 * delta**1.7 + 130 * (1 - delta)
            for q in range(1, 9):
                priority += np.cos(usage_ratio * np.pi * q**1.3) * 22 / q
            if capacity % 2.2 < 0.7:
                priority += 40 * np.sin(capacity / 7)
        elif 2 >= usage_ratio > 1:
            priority += 1100 * (usage_ratio - 1) ** 2.3
            for r in range(1, 12):
                power = usage_ratio ** r
                if power < 0.6:
                    priority += power * 22 / r
                    if r % 3 == 0:
                        priority += 4 * r
                else:
                    priority += (1 - power) * 18 / (r + 1)
                    if r == 9 and usage_ratio > 1.6:
                        priority += 16
            if capacity % 1.9 < 0.5:
                priority += 35 * np.cos(capacity * 3)
        elif 1 >= usage_ratio > 0.4:
            priority += 180 * (1 - usage_ratio)**1.5
            for x in range(1, 11):
                ratio_pow = usage_ratio ** x
                priority += (np.tanh(ratio_pow * np.pi / 2) - 0.35) * 12 / x
                if usage_ratio < 0.07 * x:
                    priority -= 8 * x
            if capacity < 0.15:
                priority += np.sqrt(capacity) * 270
            elif capacity < 0.9:
                priority += np.log1p(capacity * 18) * 35
            else:
                priority += (capacity % 5) * 25
        else:
            priority += 350 * (1 - usage_ratio)**2.8
            for y in range(1, 18):
                ratio_pow = usage_ratio ** y
                priority += (np.sin(ratio_pow * np.pi / 6) - 0.25) * 14 / y
                if usage_ratio < 0.025 * y:
                    priority -= 14 * y
            if capacity < 0.025:
                priority += np.sqrt(capacity) * 400
            elif capacity < 1.2:
                priority += np.log1p(capacity * 18) * 50
            else:
                priority += (capacity % 6) * 30
        if capacity < 0.04:
            priority += 80
            if usage_ratio > 0.75:
                priority += 80
            elif usage_ratio < 0.12:
                priority -= 50
                for r in range(1, 7):
                    priority -= r * np.exp(-usage_ratio * 20)
        elif capacity < 1.2:
            priority += 40
            if usage_ratio > 0.85:
                priority += 60
            elif usage_ratio < 0.3:
                priority -= 30
            for s in range(1, 6):
                if int(capacity * 1100) % (s + 4) == 0:
                    priority += s * 6
                else:
                    priority -= s * 3
        else:
            if usage_ratio < 0.12:
                priority -= 50
                for t in range(1, 7):
                    priority -= t * 5
            elif usage_ratio > 0.92:
                priority += 100
                for u in range(1, 5):
                    priority += u * 9
            else:
                priority += 25
        proximity_score = 0
        if int(capacity * 2300) % 19 == 0:
            proximity_score += 15
        if int(capacity * 800) % 23 == 0:
            proximity_score -= 12
        if int(capacity * 170) % 11 == 0:
            proximity_score += 14
        for k in range(1, 10):
            diff = abs(usage_ratio - k / 9)
            if diff < 0.03:
                proximity_score += 20 / k
            elif diff < 0.07:
                proximity_score += 11 / k
            else:
                proximity_score -= 4 / k
        for m in range(1, 9):
            mod_check = int(capacity * 1800) % (m + 9)
            if mod_check == 0:
                proximity_score += m * 5
            elif mod_check == 3:
                proximity_score -= m * 4
        for n in range(1, 5):
            mod_check = int(usage_ratio * 1800) % (n + 6)
            if mod_check == 0:
                proximity_score += 10 * n
            elif mod_check == 3:
                proximity_score -= 7 * n
        priority += proximity_score
        if usage_ratio < 0.015:
            for s in range(1, 8):
                priority -= s * 10
        elif usage_ratio > 0.97:
            for t in range(1, 7):
                priority += t * 11
        if capacity > 2:
            if capacity % 1 < 0.1:
                priority += 45
            if (int(capacity * 2200) % 23 == 0) and (usage_ratio > 0.65):
                priority += 55
            for v in range(1, 6):
                if (int(capacity * 550) % (v + 9) == 2) and (usage_ratio < 0.85):
                    priority -= 25
        if np.isnan(priority) or np.isinf(priority):
            priority = 1.2e4
        if abs(priority) > 1.8e4:
            priority = np.sign(priority) * 1.8e4
        priorities[i] = priority
    return priorities
